# JsonValueError
# We want to define each variant as a nested class that's also a subclass,
# which is tricky in Python.  To accomplish this we're going to create each
# class separately, then manually add the child classes to the base class's
# __dict__.  All of this happens in dummy class to avoid polluting the module
# namespace.
class JsonValueError(Exception):
    pass

_UniffiTempJsonValueError = JsonValueError

class JsonValueError:  # type: ignore

    class Invalid(_UniffiTempJsonValueError):

        def __init__(self, reason):
            super().__init__(", ".join([
                "reason={!r}".format(reason),
            ]))
            self.reason = reason

        def __repr__(self):
            return "JsonValueError.Invalid({})".format(str(self))
    _UniffiTempJsonValueError.Invalid = Invalid # type: ignore

JsonValueError = _UniffiTempJsonValueError # type: ignore
del _UniffiTempJsonValueError


class _UniffiFfiConverterTypeJsonValueError(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        variant = buf.read_i32()
        if variant == 1:
            return JsonValueError.Invalid(
                _UniffiFfiConverterString.read(buf),
            )
        raise InternalError("Raw enum value doesn't match any cases")

    @staticmethod
    def check_lower(value):
        if isinstance(value, JsonValueError.Invalid):
            _UniffiFfiConverterString.check_lower(value.reason)
            return

    @staticmethod
    def write(value, buf):
        if isinstance(value, JsonValueError.Invalid):
            buf.write_i32(1)
            _UniffiFfiConverterString.write(value.reason, buf)

